const crypto = require('crypto');
const body = $input.first().json.body || $input.first().json;
const sig = $input.first().headers['x-hub-signature-256'];
const expected = 'sha256=' + crypto.createHmac('sha256', $env.N8N_SECRET)
  .update(JSON.stringify(body)).digest('hex');
if (sig !== expected) throw new Error('Invalid HMAC signature');

// Split pipe-separated file paths into individual items
const filesStr = body.files || '';
const files = filesStr.split('|').filter(Boolean);

return files.map(filePath => ({
  json: {
    filePath: filePath.trim(),
    commit_sha: body.commit_sha,
    pusher: body.pusher
  }
}));

const response = $input.first().json;
const prevItem = $('Verify HMAC').first().json;

// Handle HTTP errors (file not found, etc.)
if (response.statusCode && response.statusCode >= 400) {
  return [{ json: {
    filePath: prevItem.filePath,
    commit_sha: prevItem.commit_sha,
    pusher: prevItem.pusher,
    error: `HTTP ${response.statusCode}: ${response.message || 'Unknown error'}`,
    skip_parse: true
  }}];
}

let content, sha;
try {
  sha = response.sha;
  content = Buffer.from(response.content, 'base64').toString('utf8');
} catch (e) {
  return [{ json: {
    filePath: prevItem.filePath,
    commit_sha: prevItem.commit_sha,
    error: 'Could not decode file content: ' + e.message,
    skip_parse: true
  }}];
}

// Extract YAML frontmatter between --- delimiters
const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
if (!fmMatch) {
  return [{ json: {
    filePath: prevItem.filePath,
    commit_sha: prevItem.commit_sha,
    error: 'No YAML frontmatter found',
    skip_parse: true
  }}];
}

// Simple YAML parser for flat key: value pairs
const yamlStr = fmMatch[1];
const parsed = {};
for (const line of yamlStr.split('\n')) {
  const trimmed = line.replace(/#.*$/, '').trim();
  if (!trimmed) continue;
  const colonIdx = trimmed.indexOf(':');
  if (colonIdx === -1) continue;
  const key = trimmed.substring(0, colonIdx).trim();
  const val = trimmed.substring(colonIdx + 1).trim().replace(/^"|"$/g, '');
  // Parse arrays: [US-001, US-002]
  if (val.startsWith('[') && val.endsWith(']')) {
    const inner = val.slice(1, -1).trim();
    parsed[key] = inner ? inner.split(',').map(s => s.trim()) : [];
  } else {
    parsed[key] = val;
  }
}

return [{ json: {
  // Core identity
  id: parsed.id || '',
  type: parsed.type || '',
  project: parsed.project || '',
  title: parsed.title || '',
  status: parsed.status || 'new',
  previous_status: parsed.previous_status || '',
  priority: parsed.priority || 'medium',
  severity: parsed.severity || '',
  category: parsed.category || '',
  // Tracking fields
  processing_started: parsed.processing_started || '',
  processing_updated: parsed.processing_updated || '',
  current_agent: parsed.current_agent || '',
  last_error: parsed.last_error || '',
  api_cost_usd: parseFloat(parsed.api_cost_usd) || 0,
  retry_count: parseInt(parsed.retry_count) || 0,
  // File metadata
  filePath: prevItem.filePath,
  fileSha: sha,
  commit_sha: prevItem.commit_sha,
  pusher: prevItem.pusher,
  // Raw YAML (for agents that need it)
  _raw: parsed,
  skip_parse: false,
  error: null
}}];

const item = $input.first().json;
const processingStarted = item.processing_started;

if (processingStarted) {
  const startedAt = new Date(processingStarted);
  const now = new Date();
  const minutesSinceStart = (now - startedAt) / 1000 / 60;

  // Als het item minder dan 5 minuten geleden in verwerking is gegaan → skip
  if (minutesSinceStart < 5) {
    return [{ json: { skip: true, reason: 'already_processing', item_id: item.id, ...item } }];
  }
}

return [{ json: { ...item, skip: false } }];

// Merge lock result with original item data
const lockResult = $input.first().json;
const item = $('Deduplication Check').first().json;

return [{ json: {
  ...item,
  acquired: lockResult.acquired,
  locked_by: lockResult.locked_by || '',
  locked_at: lockResult.locked_at || ''
}}];

function calculateQueueScore(item) {
  const TYPE_WEIGHTS = {
    'bug': { 'critical': 100, 'major': 90, 'minor': 70, 'trivial': 50, '_default': 70 },
    'issue': { 'security': 95, 'performance': 65, '_default': 60 },
    'feature': { '_default': 30 },
    'story': { '_default': 20 },
    'epic': { '_default': 10 }
  };
  let typeWeight = 30;
  const typeConfig = TYPE_WEIGHTS[item.type];
  if (typeConfig) {
    if (item.type === 'bug') typeWeight = typeConfig[item.severity] || typeConfig['_default'];
    else if (item.type === 'issue') typeWeight = typeConfig[item.category] || typeConfig['_default'];
    else typeWeight = typeConfig['_default'];
  }
  const PRIORITY_WEIGHTS = { 'critical': 40, 'high': 30, 'medium': 20, 'low': 10 };
  const priorityWeight = PRIORITY_WEIGHTS[item.priority] || 20;
  if (item.status === 'deploy-failed') return typeWeight + priorityWeight + 50;
  const STATUS_WEIGHTS = { 'staging-verified': 15, 'testing': 12, 'review': 10, 'in-progress': 8, 'planned': 5, 'triaged': 3, 'new': 0 };
  const statusWeight = STATUS_WEIGHTS[item.status] || 0;
  return typeWeight + priorityWeight + statusWeight;
}

const file = $input.first().json;
const queue = JSON.parse(Buffer.from(file.content, 'base64').toString('utf8'));
const item = $('Deduplication Check').first().json;

const alreadyQueued = queue.queue.find(q => q.item_id === item.id);
if (alreadyQueued) {
  return [{ json: { enqueued: false, reason: 'already_in_queue', item_id: item.id, locked_by: item.locked_by || 'unknown' } }];
}

const queueEntry = {
  item_id: item.id,
  file_path: item.filePath,
  status: item.status,
  project: item.project,
  type: item.type || 'story',
  priority: item.priority || 'medium',
  severity: item.severity || '',
  category: item.category || '',
  queue_score: 0,
  queued_at: new Date().toISOString(),
  commit_sha: item.commit_sha || ''
};
queueEntry.queue_score = calculateQueueScore(queueEntry);

queue.queue.push(queueEntry);
queue.queue.sort((a, b) => {
  if (b.queue_score !== a.queue_score) return b.queue_score - a.queue_score;
  return new Date(a.queued_at) - new Date(b.queued_at);
});
queue.last_updated = new Date().toISOString();

const position = queue.queue.findIndex(q => q.item_id === item.id) + 1;

return [{
  json: {
    content: Buffer.from(JSON.stringify(queue, null, 2)).toString('base64'),
    sha: file.sha,
    item_id: item.id,
    queue_score: queueEntry.queue_score,
    queue_position: position,
    queue_total: queue.queue.length,
    item_type: queueEntry.type,
    locked_by: item.locked_by || 'unknown',
    enqueued: true
  }
}];

